import{c as a,Q as o,j as d,m as i}from"./chunks/framework.DVkeSyfh.js";const u=JSON.parse('{"title":"База данных и сохраняемые данные","description":"","frontmatter":{},"headers":[],"relativePath":"ru/database.md","filePath":"ru/database.md","lastUpdated":null}'),c={name:"ru/database.md"};function t(l,e,s,r,n,m){return o(),d("div",null,[...e[0]||(e[0]=[i('<h1 id="база-данных-и-сохраняемые-данные" tabindex="-1">База данных и сохраняемые данные <a class="header-anchor" href="#база-данных-и-сохраняемые-данные" aria-label="Permalink to &quot;База данных и сохраняемые данные&quot;">​</a></h1><p>Эта страница документирует текущую SQLite-схему и metadata/analysis payloads, которые сохраняются в SQLite. Используйте ее, чтобы понять, что приложение сохраняет, что удаляет reset или почему отдельный режим поиска сначала требует конкретный analysis pass.</p><h2 id="спецификация-sqlite" tabindex="-1">Спецификация SQLite <a class="header-anchor" href="#спецификация-sqlite" aria-label="Permalink to &quot;Спецификация SQLite&quot;">​</a></h2><p>Текущая schema version: <code>2</code>.</p><p>База данных - локальное состояние пользователя. Обычные workflows scan, analysis, search, reset, clear и relocation изменяют только SQLite records; они не перезаписывают аудиофайлы. Явное исключение - отдельный workflow записи MAEST genre tags, описанный в <a href="./search-and-tags.html">Поиск и запись тегов</a>.</p><h3 id="tracks" tabindex="-1"><code>tracks</code> <a class="header-anchor" href="#tracks" aria-label="Permalink to &quot;`tracks`&quot;">​</a></h3><p>Хранит одну строку на индексированный аудиофайл:</p><ul><li><code>id</code>: стабильный локальный track ID.</li><li><code>path</code>: уникальный сохраненный audio path.</li><li><code>size</code>: размер файла на момент scan.</li><li><code>mtime</code>: время изменения файла на момент scan.</li><li><code>artist</code>, <code>title</code>, <code>album</code>: выбранные file metadata.</li><li><code>bpm</code>, <code>musical_key</code>, <code>energy</code>, <code>duration</code>: рабочие поля для UI и analysis flows.</li><li><code>metadata_json</code>: JSON object для Mutagen fields и model-derived metadata.</li><li><code>created_at</code>, <code>updated_at</code>: локальные timestamps строки.</li></ul><p><code>metadata_json</code> должен быть валидным JSON. Схема содержит triggers, которые отклоняют invalid JSON при insert или update.</p><p>Используйте эту таблицу, чтобы ответить на вопросы &quot;какие треки есть в библиотеке?&quot; и &quot;какие metadata или analysis summaries UI показывает для row?&quot;. <code>path</code> - ссылка обратно на локальный аудиофайл; relocation обновляет только сохраненный путь, когда те же файлы переехали в новый root.</p><h3 id="embeddings" tabindex="-1"><code>embeddings</code> <a class="header-anchor" href="#embeddings" aria-label="Permalink to &quot;`embeddings`&quot;">​</a></h3><p>Хранит model vectors по track и embedding space:</p><ul><li><code>track_id</code>: ссылается на <code>tracks.id</code>.</li><li><code>embedding_key</code>: сейчас <code>mert</code>, <code>clap</code> или <code>maest</code>.</li><li><code>model_name</code>: идентификатор model или checkpoint.</li><li><code>dim</code>: dimension вектора.</li><li><code>vector</code>: binary float32 vector payload.</li><li><code>updated_at</code>: локальный timestamp строки.</li></ul><p>Primary key - <code>(track_id, embedding_key)</code>, поэтому один трек может иметь MERT, CLAP и MAEST vectors без смешивания этих spaces.</p><p>Используйте эту таблицу, чтобы проверить, хватает ли данных workflow на основе embeddings: MERT search требует <code>mert</code>, CLAP text search требует <code>clap</code>, а promoted combined classifiers требуют <code>mert</code> плюс <code>maest</code> вместе с Sonara features.</p><h3 id="library-settings" tabindex="-1"><code>library_settings</code> <a class="header-anchor" href="#library-settings" aria-label="Permalink to &quot;`library_settings`&quot;">​</a></h3><p>Хранит локальные database-level settings, например выбранный music root.</p><p>Используйте эту таблицу для app-level preferences, привязанных к одной базе, а не к одному track.</p><h3 id="track-classifier-scores" tabindex="-1"><code>track_classifier_scores</code> <a class="header-anchor" href="#track-classifier-scores" aria-label="Permalink to &quot;`track_classifier_scores`&quot;">​</a></h3><p>Хранит derived classifier outputs по track и classifier key:</p><ul><li><code>track_id</code>: ссылается на <code>tracks.id</code>.</li><li><code>classifier</code>: classifier key, например <code>live_instrumentation</code>.</li><li><code>score</code>: основной user-facing score для filtering.</li><li><code>label</code>: coarse label вроде <code>high</code>, <code>medium</code> или <code>low</code>.</li><li><code>confidence</code>: максимальная class probability.</li><li><code>probabilities_json</code>: classifier probabilities по training labels профиля.</li><li><code>feature_set</code>: feature family, использованная classifier artifact, сейчас <code>combined</code>.</li><li><code>model_id</code>: promoted model path, использованный для scoring.</li><li><code>analyzed_at</code>: локальный scoring timestamp.</li></ul><p>Primary key - <code>(track_id, classifier)</code>, поэтому повторный запуск classifier обновляет score для этого track вместо добавления исторических rows.</p><p>Используйте эту таблицу, когда CLASS filter ведет себя неожиданно. Missing rows обычно означают, что promoted classifier еще не оценил track или track не имел нужных Sonara, MERT или MAEST inputs во время scoring.</p><h2 id="metadata-и-analysis-data" tabindex="-1">Metadata и analysis data <a class="header-anchor" href="#metadata-и-analysis-data" aria-label="Permalink to &quot;Metadata и analysis data&quot;">​</a></h2><p>Приложение намеренно разделяет file tags и computed values.</p><p>Mutagen scanning читает фиксированный whitelist:</p><ul><li><code>artist</code></li><li><code>title</code></li><li><code>album</code></li><li><code>genre</code></li><li><code>year</code></li><li><code>country</code></li><li><code>label</code></li><li><code>catalog_number</code></li><li><code>track_number</code></li><li><code>disc_number</code></li><li><code>bpm</code></li><li><code>key</code></li><li><code>comment</code></li><li><code>isrc</code></li><li><code>duration</code></li><li><code>audio_format</code></li><li><code>audio_codec</code></li><li><code>date</code></li></ul><p>Values нормализуются в JSON-safe values перед сохранением. Mutagen-specific objects, например ID3 timestamps, конвертируются в strings.</p><p><code>RefreshTags</code> заменяет только этот subset Mutagen metadata. Он сохраняет stored paths и model analysis data.</p><p>Analysis outputs живут рядом с file tags, а не заменяют их. Поэтому track может показывать одновременно file metadata вроде <code>genre</code> или <code>bpm</code> и computed values вроде Sonara BPM, MAEST genres, embeddings или classifier scores.</p>',30)])])}const b=a(c,[["render",t]]);export{u as __pageData,b as default};
